import javax.inject._
import play.api.mvc._
import scala.concurrent.{ExecutionContext, Future}
import play.api.libs.json._
import play.modules.reactivemongo.ReactiveMongoApi

class OrderController @Inject()(val controllerComponents: ControllerComponents,
                               implicit val reactiveMongoApi: ReactiveMongoApi)(implicit ec: ExecutionContext)
  extends BaseController {
  
  import scala.concurrent.ExecutionContext.Implicits.global

  def getOrderDetails(id: String): Action[AnyContent] = Action.async { implicit request =>
    val orderCollection = reactiveMongoApi.database.getCollection("orders")
    
    // assuming the Order model has a method 'findById' which retrieves an order by its ID
    orderCollection.flatMap(_.findById[Order](id)).map{
      case Some(order) => Ok(Json.toJson(order))  // if found, return OK with the JSON of the order
      case None        => NotFound                  // If not found, return NOT_FOUND status
    }
    
  }
}